I'm unfamiliar with Django ORM's Rank, window and partitioning features - can you please explain how it works in the following class?

```py
class ShoppingCartBaseMarkup(BusinessUnitMixin, TimestampsBase, models.Model):
    created_by = models.ForeignKey(User, on_delete=models.PROTECT)
    active_period = DateTimeRangeField()

    if TYPE_CHECKING:
        rules: RelatedManager[ShoppingCartBaseMarkupRule]
        partner_rules: RelatedManager[ShoppingCartBaseMarkupPartnerRule]

    @property
    def is_active(self):
        return timezone.now() in self.active_period

    @classmethod
    def _rules_queryset(cls, address: Address | None = None):
        if address and address.point:
            return ShoppingCartBaseMarkupRule.objects.annotate(
                priority=Window(
                    Rank(),
                    order_by=Case(
                        When(named_zone__polygon__contains=address.point, then=Value(0)),
                        When(named_zone__isnull=True, then=Value(1)),
                        default=Value(2),
                    ),
                )
            ).filter(priority=1)

        return ShoppingCartBaseMarkupRule.objects.filter(named_zone__isnull=True)

    @classmethod
    def get_markup(
        cls,
        business_unit: BusinessUnit,
        active_at: datetime | None = None,
        address: Address | None = None,
    ) -> ShoppingCartBaseMarkup | None:
        active_at = active_at or timezone.now()
        return (
            cls.objects.filter(
                business_unit=business_unit.get_central_unit(), active_period__contains=active_at
            )
            .prefetch_related(
                'partner_rules',
                Prefetch('rules', queryset=cls._rules_queryset(address), to_attr='rules_prefetch'),
            )
            .first()
        )

    def get_partner_rule(self, business_unit: BusinessUnit) -> ShoppingCartBaseMarkupPartnerRule | None:
        if business_unit.is_central_unit:
            return None
        rules = self.partner_rules.all()
        return next(
            (rule for rule in rules if rule.business_unit == business_unit),
            None,
        )

    def get_rules(
        self,
        bundled: bool,
        business_unit: BusinessUnit | None,
        address: Address | None = None,
    ) -> dict[MainHardwareType, BaseMarkupRule]:
        # Only the major products have a non-bundled rule and only the inclusion of
        # two major products qualifies us to select the bundled rule
        major_products = {MainHardwareType.PV_SYSTEM, MainHardwareType.BATTERY}

        partner_markup_adjustment_pp = 0
        if business_unit and (partner_rule := self.get_partner_rule(business_unit)):
            partner_markup_adjustment_pp = partner_rule.markup_adjustment_percentage_points

        def should_select_rule(rule: ShoppingCartBaseMarkupRule) -> bool:
            """
            For rules with a standalone and a bundled version we select the applicable one,
            for the others, we select the one we have
            """
            if rule.hardware_type not in major_products:
                return True
            return rule.bundled == bundled

        if prefetched := getattr(self, 'rules_prefetch', None):
            zoned_rules = prefetched
        else:
            zoned_rules = self._rules_queryset(address).filter(base_markup=self)

        return {
            rule.hardware_type: BaseMarkupRule.from_rule(rule, partner_markup_adjustment_pp)
            for rule in zoned_rules
            if should_select_rule(rule)
        }

    def get_rules_dict(self) -> dict[str, ShoppingCartBaseMarkupRule]:
        return {rule.flat_key: rule for rule in self.rules.all() if rule.named_zone_id is None}

    def diff(self, other_markup: ShoppingCartBaseMarkup | None = None):
        from dictdiffer import diff

        def get_rules_dict(markup):
            rules = {}
            if not markup:
                return rules
            for rule in markup.rules.all():
                if rule.named_zone_id is not None:
                    continue
                rules[rule.flat_key] = model_to_dict(
                    rule,
                    fields=[
                        'markup_percent',
                        'subscription_asset_value_multiplier',
                        'minimum_base_markup',
                        'maximum_base_markup',
                    ],
                )
            for rule in markup.partner_rules.all():
                fields = ['markup_adjustment_percentage_points']
                if rule.business_unit.type.is_platform_partner:
                    fields.append('platform_partner_fixed_margin_percentage')
                rules[rule.business_unit.slug] = model_to_dict(rule, fields=fields)
            return rules

        self_rules = get_rules_dict(self)
        other_rules = get_rules_dict(other_markup)

        differences: dict[str, dict[str, tuple[Any, Any]]] = defaultdict(dict)
        for action, key, data in diff(other_rules, self_rules):
            if action == 'change':
                group, field = key.split('.', maxsplit=1)
                differences[group][field] = data
            elif action == 'add':
                for key, fields in data:
                    differences[key] |= {k: (None, v) for k, v in fields.items() if v is not None}
        return differences

    class Meta:
        # Hoping to rename this model to BaseMarkup
        db_table = 'shoppingcart_basemarkup'
        constraints = [
            ExclusionConstraint(
                name='exclude_overlapping_periods_per_businessunit',
                expressions=[
                    ('active_period', RangeOperators.OVERLAPS),
                    ('business_unit', RangeOperators.EQUAL),
                ],
            ),
            CheckConstraint(
                check=Q(active_period__isempty=False),
                name='active_period_not_empty',
            ),
        ]


